// ─── PROMPTPAY QR GENERATOR ────────────────────────────────────────────────
function generatePromptPayPayload(phone, amount) {
  const cleanPhone = phone.replace(/\D/g, "");
  const formattedPhone = "0066" + cleanPhone.slice(1);
  
  const formatField = (id, value) => {
    const len = value.length.toString().padStart(2, "0");
    return id + len + value;
  };
  
  const merchantInfo = formatField("00", "A000000677010111") +
                       formatField("01", formattedPhone);
  const payload = formatField("00", "01") +
                  formatField("01", "12") +
                  formatField("29", merchantInfo) +
                  "5303764" +
                  (amount ? formatField("54", amount.toFixed(2)) : "") +
                  "5802TH" +
                  formatField("59", "Tabletennis SC") +
                  formatField("60", "Bangkok") +
                  "6304";

  const crc = crc16(payload);
  return payload + crc;
}

function crc16(str) {
  let crc = 0xFFFF;
  for (let i = 0; i < str.length; i++) {
    crc ^= str.charCodeAt(i) << 8;
    for (let j = 0; j < 8; j++) {
      crc = (crc & 0x8000) ? ((crc << 1) ^ 0x1021) : (crc << 1);
    }
  }
  return (crc & 0xFFFF).toString(16).toUpperCase().padStart(4, "0");
}

function QRCodeDisplay({ payload }) {
  const qrUrl = `https://api.qrserver.com/v1/create-qr-code/?size=240x240&data=${encodeURIComponent(payload)}&bgcolor=ffffff&color=05080f&margin=10`;
  return (
    <div style={{ background: "#fff", borderRadius: 16, padding: 12, display: "inline-block", boxShadow: "0 0 40px rgba(0,229,153,0.2)" }}>
      <img src={qrUrl} alt="PromptPay QR" style={{ width: 220, height: 220, display: "block" }} />
    </div>
  );
}

