// ─── HOOKS ─────────────────────────────────────────────────────────────────
function useSheets() {
  const [programs, setPrograms] = useState(FALLBACK_PROGRAMS);
  const [freeResources, setFreeResources] = useState(FALLBACK_FREE);
  const [loading, setLoading] = useState(false);
  const [connected, setConnected] = useState(false);

  useEffect(() => {
    if (APPS_SCRIPT_URL.includes("YOUR_SCRIPT_ID")) return;
    setLoading(true);
    Promise.all([
      fetch(`${APPS_SCRIPT_URL}?sheet=Programs`).then(r => r.json()).catch(() => null),
      fetch(`${APPS_SCRIPT_URL}?sheet=FreeResources`).then(r => r.json()).catch(() => null),
    ]).then(([prog, free]) => {
      if (prog?.data) { setPrograms(prog.data); setConnected(true); }
      if (free?.data) setFreeResources(free.data);
    }).finally(() => setLoading(false));
  }, []);

  const addMember = useCallback(async (member) => {
    if (APPS_SCRIPT_URL.includes("YOUR_SCRIPT_ID")) return true;
    try { await fetch(APPS_SCRIPT_URL, { method: "POST", body: JSON.stringify({ action: "addMember", ...member }) }); return true; }
    catch { return false; }
  }, []);

  const addOrder = useCallback(async (order) => {
    if (APPS_SCRIPT_URL.includes("YOUR_SCRIPT_ID")) return true;
    try { await fetch(APPS_SCRIPT_URL, { method: "POST", body: JSON.stringify({ action: "addOrder", ...order }) }); return true; }
    catch { return false; }
  }, []);

  return { programs, freeResources, loading, connected, addMember, addOrder };
}

