// ─── FREE RESOURCES ────────────────────────────────────────────────────────
function FreeResourcesPage({ user, setPage, freeResources }) {
  const [downloading, setDownloading] = useState(null);
  const handleDownload = (r) => {
    if (!user) { setPage("login"); return; }
    setDownloading(r.id);
    if (r.fileUrl && r.fileUrl !== "#") window.open(r.fileUrl, "_blank");
    setTimeout(() => setDownloading(null), 2000);
  };
  return (
    <section style={{ minHeight: "100vh", background: "#05080f", padding: "100px 24px 80px" }}>
      <div style={{ maxWidth: 1000, margin: "0 auto" }}>
        <div style={{ display: "flex", alignItems: "center", gap: 16, marginBottom: 12 }}>
          <Logo size={48} withGlow />
          <div>
            <p style={{ color: "#00e599", fontFamily: "'Bebas Neue', sans-serif", letterSpacing: 3, margin: 0 }}>FREE DOWNLOADS</p>
            <h2 style={{ fontFamily: "'Bebas Neue', sans-serif", fontSize: "clamp(28px,4vw,52px)", color: "#fff", margin: 0 }}>FREE RESOURCES</h2>
          </div>
        </div>
        <p style={{ color: "#64748b", marginBottom: 48, fontFamily: "'DM Sans', sans-serif" }}>{user ? `Welcome back, ${user.name}!` : "Create a free account to access all downloadable resources."}</p>
        <div style={{ display: "grid", gap: 20 }}>
          {freeResources.map((r) => (
            <div key={r.id} style={{ background: "rgba(255,255,255,0.03)", border: "1px solid rgba(255,255,255,0.08)", borderRadius: 20, padding: "28px 32px", display: "flex", alignItems: "center", justifyContent: "space-between", gap: 24 }}>
              <div style={{ display: "flex", alignItems: "center", gap: 20 }}>
                <div style={{ width: 52, height: 52, borderRadius: 14, background: "rgba(0,229,153,0.1)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 24 }}>{r.icon}</div>
                <div>
                  <div style={{ color: "#fff", fontWeight: 700, fontFamily: "'DM Sans', sans-serif", marginBottom: 4 }}>{r.title}</div>
                  <div style={{ color: "#64748b", fontSize: 14, fontFamily: "'DM Sans', sans-serif", maxWidth: 480 }}>{r.desc}</div>
                  <div style={{ color: "#00e599", fontSize: 12, marginTop: 6, fontFamily: "'Bebas Neue', sans-serif", letterSpacing: 1 }}>📄 {r.pages} · FREE</div>
                </div>
              </div>
              <button onClick={() => handleDownload(r)} style={{ background: downloading === r.id ? "rgba(0,229,153,0.2)" : "linear-gradient(135deg,#00e599,#00b4d8)", border: "none", color: downloading === r.id ? "#00e599" : "#05080f", padding: "12px 28px", borderRadius: 10, cursor: "pointer", fontFamily: "'Bebas Neue', sans-serif", fontSize: 13, letterSpacing: 1.5, whiteSpace: "nowrap", minWidth: 140 }}>
                {downloading === r.id ? "✓ DOWNLOADED" : user ? "DOWNLOAD PDF" : "LOGIN TO GET"}
              </button>
            </div>
          ))}
        </div>
        {!user && (
          <div style={{ marginTop: 40, padding: 32, borderRadius: 20, background: "rgba(0,229,153,0.06)", border: "1px solid rgba(0,229,153,0.2)", textAlign: "center" }}>
            <p style={{ color: "#fff", fontFamily: "'DM Sans', sans-serif", marginBottom: 16 }}>🔒 Create a free account to access all resources</p>
            <button onClick={() => setPage("signup")} style={{ background: "linear-gradient(135deg,#00e599,#00b4d8)", border: "none", color: "#05080f", padding: "12px 32px", borderRadius: 10, cursor: "pointer", fontFamily: "'Bebas Neue', sans-serif", fontSize: 15, letterSpacing: 2 }}>CREATE FREE ACCOUNT</button>
          </div>
        )}
      </div>
    </section>
  );
}

// ─── STORE ─────────────────────────────────────────────────────────────────
function StorePage({ programs, addOrder, user, setPage }) {
  const [paymentProduct, setPaymentProduct] = useState(null);

  const handleBuyNow = (p) => {
    if (!user) { setPage("login"); return; }
    setPaymentProduct(p);
  };

  const handlePaymentConfirm = async ({ product }) => {
    await addOrder({
      productId: product.id, productTitle: product.title,
      price: product.price, buyerEmail: user?.email || "",
      buyerName: user?.name || "", date: new Date().toISOString(),
      status: "slip_submitted",
    });
  };

  return (
    <>
      {paymentProduct && (
        <PaymentModal
          product={paymentProduct}
          user={user}
          onClose={() => setPaymentProduct(null)}
          onConfirm={handlePaymentConfirm}
        />
      )}
      <section style={{ minHeight: "100vh", background: "#05080f", padding: "100px 24px 80px" }}>
        <div style={{ maxWidth: 1200, margin: "0 auto" }}>
          <div style={{ display: "flex", alignItems: "center", gap: 16, marginBottom: 12 }}>
            <Logo size={48} withGlow />
            <div>
              <p style={{ color: "#00e599", fontFamily: "'Bebas Neue', sans-serif", letterSpacing: 3, margin: 0 }}>PREMIUM PROGRAMS</p>
              <h2 style={{ fontFamily: "'Bebas Neue', sans-serif", fontSize: "clamp(28px,4vw,52px)", color: "#fff", margin: 0 }}>ELITE TRAINING SYSTEMS</h2>
            </div>
          </div>
          <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 48 }}>
            <p style={{ color: "#64748b", fontFamily: "'DM Sans', sans-serif", margin: 0 }}>ชำระผ่าน PromptPay · รับไฟล์ทันทีหลังยืนยัน</p>
            <span style={{ background: "rgba(0,229,153,0.1)", border: "1px solid rgba(0,229,153,0.3)", color: "#00e599", fontSize: 11, padding: "3px 10px", borderRadius: 100, fontFamily: "'Bebas Neue', sans-serif", letterSpacing: 1 }}>PROMPTPAY ✓</span>
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(500px, 1fr))", gap: 28 }}>
            {programs.map((p) => (
              <div key={p.id} style={{ background: "rgba(255,255,255,0.03)", border: "1px solid rgba(255,255,255,0.08)", borderRadius: 24, overflow: "hidden" }}>
                <div style={{ padding: "28px 32px 0", display: "flex", alignItems: "flex-start", justifyContent: "space-between" }}>
                  <div style={{ display: "flex", alignItems: "center", gap: 14 }}>
                    <div style={{ width: 50, height: 50, borderRadius: 12, background: "rgba(0,229,153,0.1)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 24 }}>{p.icon}</div>
                    {p.badge && <span style={{ background: p.badge === "BESTSELLER" ? "linear-gradient(135deg,#00e599,#00b4d8)" : "rgba(255,180,0,0.2)", color: p.badge === "BESTSELLER" ? "#05080f" : "#ffb400", padding: "3px 10px", borderRadius: 100, fontSize: 10, fontFamily: "'Bebas Neue', sans-serif", letterSpacing: 1.5 }}>{p.badge}</span>}
                  </div>
                  <div style={{ textAlign: "right" }}>
                    <div style={{ color: "#00e599", fontFamily: "'Bebas Neue', sans-serif", fontSize: 26, lineHeight: 1 }}>฿{Number(p.price).toLocaleString()}</div>
                    <div style={{ color: "#64748b", fontSize: 12, fontFamily: "'DM Sans', sans-serif" }}>THB · one-time</div>
                  </div>
                </div>
                <div style={{ padding: "20px 32px" }}>
                  <h3 style={{ color: "#fff", fontFamily: "'Bebas Neue', sans-serif", fontSize: 20, letterSpacing: 1, margin: "0 0 10px" }}>{p.title}</h3>
                  <p style={{ color: "#64748b", fontSize: 14, lineHeight: 1.7, fontFamily: "'DM Sans', sans-serif", margin: "0 0 20px" }}>{p.desc}</p>
                  <div style={{ display: "flex", flexWrap: "wrap", gap: 8, marginBottom: 24 }}>
                    {(Array.isArray(p.includes) ? p.includes : (p.includes || "").split(",")).map((item) => (
                      <span key={item} style={{ background: "rgba(255,255,255,0.05)", border: "1px solid rgba(255,255,255,0.08)", color: "#94a3b8", fontSize: 12, padding: "4px 12px", borderRadius: 100, fontFamily: "'DM Sans', sans-serif" }}>✓ {item.trim()}</span>
                    ))}
                  </div>
                  <button onClick={() => handleBuyNow(p)} style={{ width: "100%", background: "linear-gradient(135deg,#00e599,#00b4d8)", border: "none", color: "#05080f", padding: "14px", borderRadius: 12, cursor: "pointer", fontFamily: "'Bebas Neue', sans-serif", fontSize: 15, letterSpacing: 2 }}>
                    {user ? "BUY NOW · จ่ายผ่าน PromptPay" : "LOGIN TO BUY"}
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>
    </>
  );
}

// ─── AUTH ──────────────────────────────────────────────────────────────────
const inputStyle = { background: "rgba(255,255,255,0.05)", border: "1px solid rgba(255,255,255,0.1)", borderRadius: 10, padding: "14px 16px", color: "#fff", fontSize: 15, outline: "none", fontFamily: "'DM Sans', sans-serif", width: "100%", boxSizing: "border-box" };

function AuthPage({ mode, setPage, setUser, addMember }) {
  const [form, setForm] = useState({ name: "", email: "", password: "" });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const isLogin = mode === "login";

  const handleSubmit = async () => {
    if (!form.email || !form.password || (!isLogin && !form.name)) { setError("Please fill in all fields."); return; }
    setLoading(true);
    if (!isLogin) await addMember({ name: form.name, email: form.email, date: new Date().toISOString() });
    setTimeout(() => { setUser({ name: isLogin ? form.email.split("@")[0] : form.name, email: form.email }); setPage("home"); setLoading(false); }, 1200);
  };

  return (
    <section style={{ minHeight: "100vh", display: "flex", alignItems: "center", justifyContent: "center", background: "radial-gradient(ellipse 60% 50% at 50% 0%, rgba(0,229,153,0.12) 0%, transparent 60%), #05080f", padding: "80px 24px" }}>
      <div style={{ width: "100%", maxWidth: 440, background: "rgba(255,255,255,0.03)", border: "1px solid rgba(255,255,255,0.1)", borderRadius: 28, padding: "48px 40px" }}>
        <div style={{ textAlign: "center", marginBottom: 36 }}>
          <div style={{ display: "flex", justifyContent: "center", marginBottom: 16 }}><Logo size={72} withGlow /></div>
          <h2 style={{ fontFamily: "'Bebas Neue', sans-serif", fontSize: 34, color: "#fff", margin: "0 0 6px", letterSpacing: 2 }}>{isLogin ? "WELCOME BACK" : "JOIN NOW"}</h2>
          <p style={{ color: "#64748b", fontSize: 14, fontFamily: "'DM Sans', sans-serif" }}>{isLogin ? "Sign in to your account" : "Create your free account"}</p>
        </div>
        <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>
          {!isLogin && <input placeholder="Full Name" value={form.name} onChange={e => setForm({ ...form, name: e.target.value })} style={inputStyle} />}
          <input placeholder="Email Address" type="email" value={form.email} onChange={e => setForm({ ...form, email: e.target.value })} style={inputStyle} />
          <input placeholder="Password" type="password" value={form.password} onChange={e => setForm({ ...form, password: e.target.value })} style={inputStyle} />
          {error && <p style={{ color: "#f87171", fontSize: 13, fontFamily: "'DM Sans', sans-serif" }}>{error}</p>}
          <button onClick={handleSubmit} style={{ background: "linear-gradient(135deg,#00e599,#00b4d8)", border: "none", color: "#05080f", padding: "15px", borderRadius: 12, cursor: loading ? "not-allowed" : "pointer", fontFamily: "'Bebas Neue', sans-serif", fontSize: 17, letterSpacing: 2, opacity: loading ? 0.7 : 1, marginTop: 8 }}>
            {loading ? "PLEASE WAIT..." : isLogin ? "SIGN IN" : "CREATE ACCOUNT"}
          </button>
        </div>
        <p style={{ color: "#64748b", fontSize: 13, textAlign: "center", marginTop: 24, fontFamily: "'DM Sans', sans-serif" }}>
          {isLogin ? "Don't have an account? " : "Already have an account? "}
          <span onClick={() => setPage(isLogin ? "signup" : "login")} style={{ color: "#00e599", cursor: "pointer" }}>{isLogin ? "Sign up free" : "Sign in"}</span>
        </p>
      </div>
    </section>
  );
}

// ─── FOOTER ────────────────────────────────────────────────────────────────
function Footer({ setPage }) {
  return (
    <footer style={{ background: "#030507", borderTop: "1px solid rgba(255,255,255,0.06)", padding: "48px 24px" }}>
      <div style={{ maxWidth: 1200, margin: "0 auto", display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: 24 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 14 }}>
          <Logo size={44} />
          <div>
            <div style={{ fontFamily: "'Bebas Neue', sans-serif", fontSize: 18, color: "#fff", letterSpacing: 2 }}>TABLETENNIS_SC</div>
            <p style={{ color: "#64748b", fontSize: 12, fontFamily: "'DM Sans', sans-serif", margin: 0 }}>ชำระเงินผ่าน PromptPay · ปลอดภัย 100%</p>
          </div>
        </div>
        <div style={{ display: "flex", gap: 24 }}>
          {["home", "free", "store", "about"].map(p => (
            <span key={p} onClick={() => setPage(p)} style={{ color: "#64748b", fontFamily: "'Bebas Neue', sans-serif", letterSpacing: 1.5, cursor: "pointer", fontSize: 13, textTransform: "uppercase" }}>{p}</span>
          ))}
        </div>
        <p style={{ color: "#374151", fontSize: 12, fontFamily: "'DM Sans', sans-serif" }}>© 2025 Tabletennis_SC. All rights reserved.</p>
      </div>
    </footer>
  );
}

// ─── APP ───────────────────────────────────────────────────────────────────
export default function App() {
  const [page, setPage] = useState("home");
  const [user, setUser] = useState(null);
  const { programs, freeResources, loading, connected, addMember, addOrder } = useSheets();

  useEffect(() => {
    const link = document.createElement("link");
    link.href = "https://fonts.googleapis.com/css2?family=Bebas+Neue&family=DM+Sans:wght@400;500;700&display=swap";
    link.rel = "stylesheet";
    document.head.appendChild(link);
  }, []);

  const renderPage = () => {
    switch (page) {
      case "home": return <><HeroSection setPage={setPage} /><AboutSection /></>;
      case "free": return <FreeResourcesPage user={user} setPage={setPage} freeResources={freeResources} />;
      case "store": return <StorePage programs={programs} addOrder={addOrder} user={user} setPage={setPage} />;
      case "about": return <AboutSection />;
      case "login": return <AuthPage mode="login" setPage={setPage} setUser={setUser} addMember={addMember} />;
      case "signup": return <AuthPage mode="signup" setPage={setPage} setUser={setUser} addMember={addMember} />;
      default: return <HeroSection setPage={setPage} />;
    }
  };

  return (
    <div style={{ background: "#05080f", minHeight: "100vh", fontFamily: "'DM Sans', sans-serif" }}>
      <Navbar page={page} setPage={setPage} user={user} setUser={setUser} connected={connected} loading={loading} />
      <main>{renderPage()}</main>
      <Footer setPage={setPage} />
    </div>
  );
}
